#include <stdio.h>
#include <stdlib.h>
#define MAX 100001
typedef struct Node {
    int val;
    struct Node* next;
} Node;
Node* createNode(int val) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->val = val;
    newNode->next = NULL;
    return newNode;
}
void insertNode(Node** head, int val) {
    Node* newNode = createNode(val);
    if (*head == NULL)
        *head = newNode;
    else {
        Node* last = *head;
        while (last->next)
            last = last->next;
        last->next = newNode;
    }
}
int main() {
    int n;
    scanf("%d", &n);
    Node** tree = (Node**) malloc(n * sizeof(Node*));
    for (int i = 0; i < n - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        insertNode(&tree[u - 1], v - 1);
        insertNode(&tree[v - 1], u - 1);
    }
    int m;
    scanf("%d", &m);
    for (int i = 0; i < m; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        // propagate and find minimum distance
    }
    return 0;
}

